"""
RL/agent.py — Hybrid inference + training script.

When imported as a module (e.g. by the competition runner):
    The `act(obs)` function is used for inference using the embedded model.

When executed directly (`python -m RL.agent`):
    Runs the full PPO training loop against 3 TacticalRuleAgent opponents.
"""


import base64
from io import BytesIO
from collections import deque

from stable_baselines3 import PPO
from stable_baselines3.common.callbacks import CheckpointCallback

from game import BomberEnv
from smarter_rule_agent import SmarterRuleAgent

# ── Embedded model weights ────────────────────────────────────────────────────
# After training, paste the base64-encoded contents of bomber_final_agent.zip here.
BRAIN_BASE64 = ""

# Module-level cached model (loaded once on first call to act())
_model = None


# ── Inference interface ───────────────────────────────────────────────────────

class Agent:
    """Tournament-compatible agent wrapper."""

    team_id = "RL_PPO_Agent"

    def __init__(self, agent_id: int):
        self.agent_id = agent_id

    # ── BFS movement constants (shared with helpers) ─────────────────────
    _MOVES = {
        0: (0, 0),
        1: (-1, 0),
        2: (1, 0),
        3: (0, -1),
        4: (0, 1),
    }

    def act(self, obs: dict) -> int:
        """
        Tournament entry-point.  Decision pipeline:

          1. Lazy-load the PPO model from BRAIN_BASE64 (once).
          2. Normalise bombs array to fixed (169, 4) shape for the model.
          3. Parse grid / players / bombs into Python structures.
          4. Compute danger_soon / danger_now with proper per-bomb blast radii.
          5. [SAFEGUARD] If already in danger -> best escape action immediately.
          6. [BFS] When safe, navigate toward items (tile 3/4) or enemies.
               - BFS path found -> candidate action.
               - BFS completely blocked by boxes -> try box-bomb path-clearing.
          7. [PPO FALLBACK] Let the model predict if BFS found nothing.
          8. [SAFEGUARD] Final gate on the chosen action:
               a. Movement (1-4): if target tile is in danger, redirect to
                  best-escape or STOP.
               b. PLACE_BOMB (5): simulate blast + look-ahead escape.  If no
                  escape exists, cancel and redirect to best-escape or STOP.
          9. Return the vetted action as a clean integer in [0, 5].
        """
        import numpy as np
        global _model

        # -- 1. Lazy model loading -------------------------------------------
        if _model is None:
            if not BRAIN_BASE64:
                return 0
            try:
                model_bytes = BytesIO(base64.b64decode(BRAIN_BASE64))
                _model = PPO.load(model_bytes)
            except Exception as e:
                print("Error loading model:", e)
                return 0

        # -- 2. Normalise observations for the PPO model ---------------------
        BOMBS_MAX = 169  # 13 x 13
        norm = {key: np.asarray(val, dtype=np.int8) for key, val in obs.items()}

        bombs_raw = norm.get("bombs", np.full((BOMBS_MAX, 4), -1, dtype=np.int8))
        if bombs_raw.ndim == 1:
            bombs_raw = (
                bombs_raw.reshape(1, 4)
                if bombs_raw.shape[0] == 4
                else np.full((BOMBS_MAX, 4), -1, dtype=np.int8)
            )
        if bombs_raw.ndim == 2 and bombs_raw.shape[1] == 4:
            n = bombs_raw.shape[0]
            if n < BOMBS_MAX:
                obs_bombs = np.concatenate(
                    [bombs_raw, np.full((BOMBS_MAX - n, 4), -1, dtype=np.int8)], axis=0
                )
            elif n > BOMBS_MAX:
                obs_bombs = bombs_raw[:BOMBS_MAX]
            else:
                obs_bombs = bombs_raw
        else:
            obs_bombs = np.full((BOMBS_MAX, 4), -1, dtype=np.int8)
        norm["bombs"] = obs_bombs

        # -- 3. Parse game state ---------------------------------------------
        try:
            grid = np.asarray(
                obs.get("map", np.zeros((13, 13), dtype=np.int8)), dtype=np.int8
            )
            if grid.ndim == 3:
                grid = grid[0]

            players_raw = np.asarray(
                obs.get("players", np.full((4, 5), -1, dtype=np.int8)), dtype=np.int8
            )
            if players_raw.ndim == 3:
                players_raw = players_raw[0]

            active_bombs = np.asarray(
                obs.get("bombs", np.full((0, 4), -1, dtype=np.int8)), dtype=np.int8
            )
            if active_bombs.ndim == 3:
                active_bombs = active_bombs[0]

            # Filter out padding rows (sentinel bx = -1)
            active_bombs = [
                b for b in active_bombs
                if int(b[0]) >= 0 and int(b[2]) > 0
            ]

            agent_idx = 0
            if agent_idx >= len(players_raw) or int(players_raw[agent_idx][2]) != 1:
                # Agent is dead -- let PPO decide (it will output 0)
                action, _ = _model.predict(norm, deterministic=True)
                return int(action)

            my_x         = int(players_raw[agent_idx][0])
            my_y         = int(players_raw[agent_idx][1])
            my_pos       = (my_x, my_y)
            bombs_left   = int(players_raw[agent_idx][3])
            bomb_bonus   = int(players_raw[agent_idx][4])
            bomb_radius  = max(1, bomb_bonus + 1)

            # Enemy positions (alive only)
            enemies = [
                (int(players_raw[i][0]), int(players_raw[i][1]))
                for i in range(len(players_raw))
                if i != agent_idx and int(players_raw[i][2]) == 1
            ]
            occupied = set(enemies)
            bomb_set = {(int(b[0]), int(b[1])) for b in active_bombs}
            blocked  = occupied | bomb_set
            blocked.discard(my_pos)

            # -- 4. Compute danger zones -------------------------------------
            danger_soon, danger_now = self._danger_tiles(
                grid, active_bombs, players_raw
            )

            # -- 5. SAFEGUARD: escape immediately if already in danger -------
            if my_pos in danger_now or my_pos in danger_soon:
                escape = self._best_escape_action(
                    grid, my_pos, blocked, danger_now, danger_soon
                )
                if escape is None:
                    escape = self._move_to_nearest_safe(
                        grid, my_pos, blocked, danger_soon, search_depth=8
                    )
                if escape is None:
                    loose = [
                        a for a in self._valid_actions(grid, my_pos, blocked)
                        if a != 0
                        and self._next_pos(my_pos, a) not in danger_now
                    ]
                    escape = loose[0] if loose else None
                return int(escape) if escape is not None else 0

            # -- 6. BFS navigation (safe zone only) --------------------------
            item_targets = {
                (x, y)
                for x in range(grid.shape[0])
                for y in range(grid.shape[1])
                if int(grid[x, y]) in (3, 4)
            }
            enemy_targets = set(enemies)

            candidate_action = None  # Will be vetted in step 8

            if item_targets:
                bfs_action = self._move_toward_targets(
                    grid, my_pos, item_targets, occupied, danger_soon
                )
                if bfs_action is not None:
                    candidate_action = bfs_action

            if candidate_action is None and enemy_targets:
                bfs_action = self._move_toward_targets(
                    grid, my_pos, enemy_targets, set(), danger_soon
                )
                if bfs_action is not None:
                    candidate_action = bfs_action

            # -- SAFEGUARD 3: box-bomb to clear a blocked path ---------------
            # BFS found no walkable route -> check if an adjacent box can be
            # bombed to open the path, provided we can escape afterwards.
            if candidate_action is None and bombs_left > 0 and my_pos not in bomb_set:
                box_adj = any(
                    0 <= nx < grid.shape[0]
                    and 0 <= ny < grid.shape[1]
                    and int(grid[nx, ny]) == 2
                    for a in (1, 2, 3, 4)
                    for nx, ny in [self._next_pos(my_pos, a)]
                )
                if box_adj and self._can_escape_after_placing(
                    grid, my_pos, blocked, danger_soon, bomb_radius
                ):
                    return 5  # Place bomb -- no further vetting needed

            # -- 7. PPO fallback ---------------------------------------------
            if candidate_action is None:
                ppo_action, _ = _model.predict(norm, deterministic=True)
                candidate_action = int(ppo_action)

            # -- 8. Final safeguard gate -------------------------------------
            action = int(candidate_action)

            # 8a. Movement safety check
            if 1 <= action <= 4:
                target = self._next_pos(my_pos, action)
                if target in danger_now or target in danger_soon:
                    safe_a = self._best_escape_action(
                        grid, my_pos, blocked, danger_now, danger_soon
                    )
                    action = int(safe_a) if safe_a is not None else 0

            # 8b. Bomb placement look-ahead escape check
            elif action == 5:
                if bombs_left <= 0 or my_pos in bomb_set:
                    safe_a = self._best_escape_action(
                        grid, my_pos, blocked, danger_now, danger_soon
                    )
                    action = int(safe_a) if safe_a is not None else 0
                elif not self._can_escape_after_placing(
                    grid, my_pos, blocked, danger_soon, bomb_radius
                ):
                    safe_a = self._best_escape_action(
                        grid, my_pos, blocked, danger_now, danger_soon
                    )
                    action = int(safe_a) if safe_a is not None else 0

            return action

        except Exception:
            # Safeguard errors must never crash the agent -- fall back to PPO
            try:
                ppo_action, _ = _model.predict(norm, deterministic=True)
                return int(ppo_action)
            except Exception:
                return 0

    # -------------------------------------------------------------------------
    # Grid / danger helpers (ported from TacticalRuleAgent)
    # -------------------------------------------------------------------------

    def _in_bounds(self, grid, x, y):
        """Return True if (x, y) is within the grid boundaries."""
        return 0 <= x < grid.shape[0] and 0 <= y < grid.shape[1]

    def _next_pos(self, pos, action):
        """Return the grid position after taking a movement action."""
        dx, dy = self._MOVES[action]
        return pos[0] + dx, pos[1] + dy

    def _passable(self, grid, x, y):
        """Return True if (x, y) is in-bounds and walkable (floor or item tile)."""
        return (
            self._in_bounds(grid, x, y)
            and int(grid[x, y]) in (0, 3, 4)
        )

    def _valid_actions(self, grid, my_pos, occupied):
        """Return the list of legal actions (always includes STOP=0)."""
        actions = [0]
        for a in (1, 2, 3, 4):
            nx, ny = self._next_pos(my_pos, a)
            if self._passable(grid, nx, ny) and (nx, ny) not in occupied:
                actions.append(a)
        return actions

    def _blast_tiles(self, grid, bx, by, radius):
        """
        Return the set of tiles hit by a bomb at (bx, by) with given radius.
        Blast stops at walls (value 1) and is blocked by boxes (value 2).
        """
        tiles = {(bx, by)}
        for dx, dy in ((-1, 0), (1, 0), (0, -1), (0, 1)):
            for r in range(1, radius + 1):
                x, y = bx + dx * r, by + dy * r
                if not self._in_bounds(grid, x, y):
                    break
                cell = int(grid[x, y])
                if cell == 1:
                    break
                tiles.add((x, y))
                if cell == 2:
                    break
        return tiles

    def _danger_tiles(self, grid, active_bombs, players_raw, default_radius=2):
        """
        Compute danger_soon (all blast zones) and danger_now (imminent,
        timer <= 1).  Uses each bomb owner's actual blast radius when available.

        Parameters
        ----------
        active_bombs : list of array-like rows [bx, by, timer, owner_id]
        players_raw  : 2-D array of shape (n_players, 5)
        """
        danger_soon = set()
        danger_now  = set()
        for b in active_bombs:
            bx, by, timer = int(b[0]), int(b[1]), int(b[2])
            if bx < 0 or timer <= 0:
                continue
            owner_id = int(b[3]) if len(b) > 3 else -1
            radius = default_radius
            if 0 <= owner_id < len(players_raw):
                radius = max(1, int(players_raw[owner_id][4]) + 1)
            blast = self._blast_tiles(grid, bx, by, radius)
            danger_soon |= blast
            if timer <= 1:
                danger_now |= blast
        return danger_soon, danger_now

    def _open_neighbors(self, grid, pos, occupied):
        """Count walkable, unoccupied neighbors of *pos*."""
        cnt = 0
        for a in (1, 2, 3, 4):
            nx, ny = self._next_pos(pos, a)
            if self._passable(grid, nx, ny) and (nx, ny) not in occupied:
                cnt += 1
        return cnt

    def _best_escape_action(self, grid, my_pos, occupied, danger_now, danger_soon):
        """
        Score each legal move and return the action that best escapes danger.
        Prefers tiles outside danger_soon; breaks ties by open-neighbor count.
        Returns None if no safe direction exists.
        """
        best_action = None
        best_score  = -(10 ** 9)
        for a in self._valid_actions(grid, my_pos, occupied):
            if a == 0:
                continue
            npos = self._next_pos(my_pos, a)
            if npos in danger_now:
                continue
            score = 0
            if npos not in danger_soon:
                score += 6
            score += self._open_neighbors(grid, npos, occupied)
            if score > best_score:
                best_score  = score
                best_action = a
        return best_action

    def _move_to_nearest_safe(self, grid, start, occupied, danger, search_depth=8):
        """
        BFS toward the nearest tile outside *danger*.  Returns the first action
        to take, or None if no reachable safe tile exists within search_depth.
        """
        q    = deque([(start, 0, None)])
        seen = {start}
        while q:
            pos, d, first_action = q.popleft()
            if pos not in danger and d > 0:
                return first_action
            if d >= search_depth:
                continue
            for a in (1, 2, 3, 4):
                nx, ny = self._next_pos(pos, a)
                npos   = (nx, ny)
                if not self._passable(grid, nx, ny) or npos in occupied or npos in seen:
                    continue
                seen.add(npos)
                q.append((npos, d + 1, a if first_action is None else first_action))
        return None

    def _can_escape_after_placing(self, grid, my_pos, occupied, danger_soon, bomb_radius):
        """
        Simulate placing a bomb at *my_pos* and check whether a safe escape
        path exists within 8 steps.
        """
        my_blast = self._blast_tiles(grid, my_pos[0], my_pos[1], bomb_radius)
        combined = set(danger_soon) | my_blast
        return (
            self._move_to_nearest_safe(grid, my_pos, occupied, combined, search_depth=8)
            is not None
        )

    def _count_boxes_in_blast(self, grid, my_pos, radius):
        """Count how many wooden boxes (value 2) the bomb at *my_pos* would hit."""
        return sum(
            1
            for x, y in self._blast_tiles(grid, my_pos[0], my_pos[1], radius)
            if int(grid[x, y]) == 2
        )

    def _box_bomb_spots(self, grid, occupied):
        """
        Return all floor tiles adjacent to at least one wooden box that are
        not currently occupied.
        """
        spots = set()
        for x in range(grid.shape[0]):
            for y in range(grid.shape[1]):
                if int(grid[x, y]) != 2:
                    continue
                for dx, dy in ((-1, 0), (1, 0), (0, -1), (0, 1)):
                    nx, ny = x + dx, y + dy
                    if self._passable(grid, nx, ny) and (nx, ny) not in occupied:
                        spots.add((nx, ny))
        return spots

    def _move_toward_targets(self, grid, start, targets, occupied, danger_soon):
        """
        BFS from *start* toward any tile in *targets*.

        Avoids *danger_soon* tiles and *occupied* cells (unless the cell is
        itself a target, e.g. an enemy standing on it).  Returns the first
        movement action (1-4) to take, or None if no path exists.
        """
        if not targets:
            return None
        q    = deque([(start, None)])
        seen = {start}
        while q:
            pos, first_action = q.popleft()
            if pos in targets and first_action is not None:
                return first_action
            for a in (1, 2, 3, 4):
                nx, ny = self._next_pos(pos, a)
                npos   = (nx, ny)
                if npos in seen:
                    continue
                if not self._passable(grid, nx, ny):
                    continue
                if npos in occupied and npos not in targets:
                    continue
                if npos in danger_soon:
                    continue
                seen.add(npos)
                q.append((npos, a if first_action is None else first_action))
        return None

def _normalize_obs(obs: dict) -> dict:
    """
    Normalise the observation dictionary to match the training format.

    The tournament runner may pass the raw game obs where 'bombs' is a
    dynamic numpy array of shape (n_active_bombs, 4).  The PPO model was
    trained with a fixed shape of (169, 4) padded with -1 sentinel rows.
    This function pads / trims 'bombs' to exactly (169, 4) so that the
    model's observation space is satisfied.
    """
    import numpy as np

    BOMBS_MAX_ROWS = 169  # 13 * 13 — same constant used in RL/game.py

    norm = {}
    for key, val in obs.items():
        norm[key] = np.asarray(val, dtype=np.int8)

    # ── Fix bombs shape ──────────────────────────────────────────────────────
    bombs = norm.get("bombs", np.full((BOMBS_MAX_ROWS, 4), -1, dtype=np.int8))

    # Handle unexpected shapes gracefully
    if bombs.ndim == 1:
        # Single bomb passed as flat array [x, y, timer, owner] → reshape
        if bombs.shape[0] == 4:
            bombs = bombs.reshape(1, 4)
        else:
            bombs = np.full((BOMBS_MAX_ROWS, 4), -1, dtype=np.int8)

    if bombs.ndim == 2 and bombs.shape[1] == 4:
        n = bombs.shape[0]
        if n < BOMBS_MAX_ROWS:
            # Pad with -1 sentinel rows
            padding = np.full((BOMBS_MAX_ROWS - n, 4), -1, dtype=np.int8)
            bombs = np.concatenate([bombs, padding], axis=0)
        elif n > BOMBS_MAX_ROWS:
            bombs = bombs[:BOMBS_MAX_ROWS]
    else:
        # Unexpected shape — fall back to empty
        bombs = np.full((BOMBS_MAX_ROWS, 4), -1, dtype=np.int8)

    norm["bombs"] = bombs
    return norm


def act(obs: dict) -> int:
    """
    Inference entry-point called by the tournament runner each step.

    Loads the model from BRAIN_BASE64 on the first call (lazy loading).
    Falls back to action 0 (STOP) if the model is not available.

    Normalises the observation before prediction so that the dynamic
    'bombs' array (shape (n, 4) from the raw game engine) is padded to
    the fixed (169, 4) shape the PPO model expects.
    """
    global _model

    if _model is None:
        if not BRAIN_BASE64:
            return 0  # No model embedded yet — default to STOP
        try:
            model_bytes = BytesIO(base64.b64decode(BRAIN_BASE64))
            _model = PPO.load(model_bytes)
        except Exception as e:
            print("Error loading model:", e)
            return 0

    # Normalise obs to match training-time observation space
    obs_norm = _normalize_obs(obs)

    action, _ = _model.predict(obs_norm, deterministic=True)
    return int(action)


# ── Training entry-point ──────────────────────────────────────────────────────

if __name__ == "__main__":
    env = BomberEnv(
        bot1=SmarterRuleAgent(agent_id=1),
        bot2=SmarterRuleAgent(agent_id=2),
        bot3=SmarterRuleAgent(agent_id=3)
    )
    
    # ── HỖ TRỢ CHECKPOINT VÀ LƯUMODEL ────────────────────────────────────
    # Sử dụng các đường dẫn chuẩn: "checkpoints" và "bomber_final_agent.zip"
    # tương đối với thư mục hiện tại khi chạy script
    CHECKPOINT_DIR = "checkpoints"
    FINAL_MODEL_PATH = "bomber_final_agent.zip"
    # ────────────────────────────────────────────────────────────────────

    checkpoint_callback = CheckpointCallback(
        save_freq=20000,
        save_path=CHECKPOINT_DIR,
        name_prefix="bomber_ppo"
    )

    # Resume từ checkpoint cũ nếu có
    latest_model_path = None
    try:
        import pathlib
        checkpoint_path = pathlib.Path(CHECKPOINT_DIR)
        if checkpoint_path.exists():
            files = sorted([f.name for f in checkpoint_path.glob("*.zip")])
            if files:
                latest_model_path = str(checkpoint_path / files[-1])
    except Exception:
        pass

    if latest_model_path:
        print(f"Resuming training from {latest_model_path}...")
        model = PPO.load(latest_model_path, env=env)
        model.learn(
            total_timesteps=1000000,
            callback=checkpoint_callback,
            reset_num_timesteps=False
        )
    else:
        print("Starting training from scratch...")
        # Thêm ent_coef để ép con AI phải làm hành động ngẫu nhiên (đặt bom thử nghiệm)
        model = PPO(
            "MultiInputPolicy", 
            env, 
            verbose=1, 
            ent_coef=0.05,
            learning_rate=0.0003
        )
        model.learn(
            total_timesteps=1000000,
            callback=checkpoint_callback
        )

    # Đổi chỗ này thành FINAL_MODEL_PATH để lưu chuẩn vị trí
    model.save(FINAL_MODEL_PATH)
    print(f"Training finished and saved to {FINAL_MODEL_PATH}")
